mapper.select:
SELECT 
FROM revenue_share_journal
WHERE author_id  = #{authorId}
  AND deleted_at IS NULL
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT journal.id, journal.order_no, journal.article_id, journal.author_id, journal.total_points, journal.platform_points, journal.author_points, journal.share_ratio, journal.settlement_status, journal.point_journal_biz_no, journal.settled_at, journal.retry_count, journal.last_error, journal.created_at, journal.deleted_at, journal.version FROM revenue_share_journal journal
INNER JOIN blog_user bu ON bu.id = journal.author_id AND bu.deleted_at IS NULL
WHERE journal.deleted_at IS NULL
AND journal.author_id = #{authorId}
AND ( bu.username LIKE CONCAT('%', #{authorKeyword}, '%') OR bu.email LIKE CONCAT('%', #{authorKeyword}, '%') )
AND journal.settlement_status = #{settlementStatus}
ORDER BY journal.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM revenue_share_journal journal

    INNER JOIN blog_user bu ON bu.id = journal.author_id AND bu.deleted_at IS NULL

WHERE journal.deleted_at IS NULL

      AND journal.author_id = #{authorId}


      AND (
          bu.username LIKE CONCAT('%', #{authorKeyword}, '%')
          OR bu.email LIKE CONCAT('%', #{authorKeyword}, '%')
      )


      AND journal.settlement_status = #{settlementStatus}
